// Check if token and hostURL are set
const token = $input.first().json.khojToken;
const hostURL = $input.first().json.hostURL;
const syncing = $input.first().json.syncing;

if (!token || !hostURL || syncing === true) {
  return { shouldContinue: false, message: 'Missing credentials or already syncing' };
}

return { shouldContinue: true };

// Collect files from configured paths
const files = $input.first().json.files || [];
const folders = $input.first().json.folders || [];
const lastSync = $input.first().json.lastSync || [];

const filesToPush = [];
const supportedExtensions = ['org', 'md', 'markdown', 'txt', 'html', 'xml', 'pdf', 'jpg', 'jpeg', 'png', 'webp', 'json', 'csv', 'py', 'js', 'java', 'cpp'];

// Add direct files
for (const file of files) {
  filesToPush.push(file.path);
}

return {
  filesToPush,
  lastSync,
  folders,
  supportedExtensions
};

// Filter files based on modification time
const filesToPush = $input.first().json.filesToPush;
const lastSync = $input.first().json.lastSync;
const regenerate = $input.first().json.regenerate || false;

const filesDataToPush = [];

for (const file of filesToPush) {
  // Check if file has been modified since last sync
  const lastSyncEntry = lastSync.find(f => f.path === file);

  // For now, mark all files as needing sync
  // In production, would check file modification time
  filesDataToPush.push({
    path: file,
    needsSync: true
  });
}

return {
  filesDataToPush,
  count: filesDataToPush.length
};

// Update last sync timestamp
const response = $input.first().json;
const filesToPush = $input.previous(1).json.filesDataToPush;

const lastSync = filesToPush
  .filter(file => true) // In production, check response.data
  .map(file => ({
    path: file.path,
    datetime: new Date().toISOString()
  }));

return {
  lastSync,
  syncCompleted: true,
  filesCount: filesToPush.length
};

// Handle sync errors
const error = $input.first().json.error;

let errorMessage = 'Sync was unsuccessful';

if (error?.response?.status === 429) {
  errorMessage = 'Out of space. Upgrade your Khoj plan to continue syncing.';
} else if (error?.code === 'ECONNREFUSED') {
  errorMessage = 'Could not connect to Khoj server. Check your host URL and network connection.';
} else if (error?.message) {
  errorMessage = error.message;
}

return {
  syncFailed: true,
  error: errorMessage,
  timestamp: new Date().toISOString()
};
